#include <bits/stdc++.h>
using namespace std;
const int MAXN=1e2+5;char c;
int n,ans=0;
bool a[MAXN][MAXN];
int f(int x,int y){
	int ans=0;
	for(int i=1;x+i<=n&&y+i<=n&&x-i>0&&y-i>0;++i){
		if(a[x+i][y+i]&&a[x-i][y+i]&&a[x+i][y-i]&&a[x-i][y-i])++ans;
		else break;
	}for(int i=1;x+i<=n&&y+i<=n&&x-i>=0&&y-i>=0;++i){
		if(a[x-i+1][y-i+1]&&a[x-i+1][y+i]&&a[x+i][y-i+1]&&a[x+i][y+i])++ans;
		else break;
	}
	return ans;
}
int main(void){
	scanf("%d",&n);
	for(int i=1;i<=n;++i){
		for(int j=1;j<=n;++j){
			cin>>c,a[i][j]=(c!='0');
		}
	}	
	for(int i=1;i<=n;++i)
		for(int j=1;j<=n;++j)
			if(a[i][j])ans+=f(i,j);
	printf("%d",ans);
	return false;
}
